7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This component convertes cartesian coordinates to polar coordinates using
11	-- a vectoring CORDIC kernel. In pipelined mode it requires more logic but
12	-- can take one input sample every clock cycle. In serial mode it requires
13	-- N clock cycles but requires less logic.
14	------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.numeric_std.all;
19	use ieee.math_real.all;
20	
21	use work.psi_fix_pkg.all;
22	use work.psi_common_array_pkg.all;
23	use work.psi_common_math_pkg.all;
24	-- @formatter:off
25	-- $$ processes=stim, resp $$
26	entity psi_fix_cordic_vect is
27	  generic(
28	    in_fmt_g          : psi_fix_fmt_t          := (1, 0, 15);                -- Must be signed                            $$ constant=(1,0,15) $$
29	    out_fmt_g         : psi_fix_fmt_t          := (0, 2, 16);                -- Must be unsigned                          $$ constant=(0,2,16) $$
30	    internal_fmt_g    : psi_fix_fmt_t          := (1, 2, 22);                -- Must be signed                            $$ constant=(1,2,22) $$
31	    angle_fmt_g       : psi_fix_fmt_t          := (0, 0, 15);                -- Must be unsigned                          $$ constant=(0,0,15) $$
32	    angle_int_fmt_g   : psi_fix_fmt_t          := (1, 0, 18);                -- Must be signed                            $$ constant=(1,0,18) $$
33	    iterations_g      : natural                := 13;                        -- number of iteration prior to get results  $$ constant=13 $$
34	    gain_comp_g       : boolean                := False;                     -- gain compensation                         $$ export=true $$
35	    round_g           : psi_fix_rnd_t          := psi_fix_trunc;             -- round or trunc                            $$ export=true $$
36	    sat_g             : psi_fix_sat_t          := psi_fix_wrap;              -- saturation or wrap                        $$ export=true $$
37	    mode_g            : string                 := "SERIAL";                  -- PIPELINED or SERIAL                       $$ export=true $$
38	    pl_stg_per_iter_g : integer range 1 to 2   := 1                          -- Number of pipeline stages per iteration (does only affect pipelined implementation)
39	  );
40	  port(
41	    clk_i     : in  std_logic;                                               -- clk system $$ type=clk; freq=100e6 $$
42	    rst_i     : in  std_logic;                                               -- rst system $$ type=rst; clk=Clk $$
43	    dat_inp_i : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);   -- data input input
44	    dat_qua_i : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0);   -- dat quadrature input
45	    vld_i     : in  std_logic;                                               -- valid signal in
46	    rdy_o     : out std_logic;                                               -- ready signal output $$ lowactive=true $$
47	    dat_abs_o : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);  -- data amplitude output
48	    dat_ang_o : out std_logic_vector(psi_fix_size(angle_fmt_g) - 1 downto 0);-- dat angle output
49	    vld_o     : out std_logic                                                -- valid output
50	  );
51	end entity;
52	-- @formatter:on
53	
54	architecture rtl of psi_fix_cordic_vect is
55	
56	  -- *** Constants ***
57	  constant AngleTableReal_c : t_areal(0 to 31) := (0.125, 0.0737918088252, 0.0389895651887, 0.0197917120803,
58	                                                   0.00993426215277, 0.00497197391179, 0.00248659363948, 0.00124337269683,
59	                                                   0.000621695834357, 0.000310849102962, 0.000155424699705, 7.77123683806e-05,
60	                                                   3.88561865063e-05, 1.94280935426e-05, 9.71404680751e-06, 4.85702340828e-06,
61	                                                   2.4285117047e-06, 1.21425585242e-06, 6.0712792622e-07, 3.03563963111e-07,
62	                                                   1.51781981556e-07, 7.58909907779e-08, 3.7945495389e-08, 1.89727476945e-08,
63	                                                   9.48637384724e-09, 4.74318692362e-09, 2.37159346181e-09, 1.1857967309e-09,
64	                                                   5.92898365452e-10, 2.96449182726e-10, 1.48224591363e-10, 7.41122956816e-11);
65	  type AngleTable_t is array (0 to iterations_g - 1) of std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
66	
67	  function AngleTableStdlv return AngleTable_t is
68	    variable Table : AngleTable_t;
69	  begin
70	    for i in 0 to iterations_g - 1 loop
71	      Table(i) := psi_fix_from_real(AngleTableReal_c(i), angle_int_fmt_g);
72	    end loop;
73	    return Table;
74	  end function;
75	
76	  constant AngleTable_c : AngleTable_t := AngleTableStdlv;
77	
78	  function CordicGain(iterations : integer) return real is
79	    variable g : real := 1.0;
80	  begin
81	    for i in 0 to iterations - 1 loop
82	      g := g * sqrt(1.0 + 2.0**(-2.0 * real(i)));
83	    end loop;
84	    return g;
85	  end function;
86	
87	  constant GcFmt_c        : psi_fix_fmt_t                                               := (0, 0, 17);
88	  constant AngleIntExtFmt : psi_fix_fmt_t                                               := (angle_int_fmt_g.S, max(angle_int_fmt_g.I, 1), angle_int_fmt_g.F);
89	  constant AbsFmt_c       : psi_fix_fmt_t                                               := (in_fmt_g.S, in_fmt_g.I + 1, in_fmt_g.F);
90	  constant GcCoef_c       : std_logic_vector(psi_fix_size(GcFmt_c) - 1 downto 0)        := psi_fix_from_real(1.0 / CordicGain(iterations_g), GcFmt_c);
91	  constant AngInt_0_5_c   : std_logic_vector(psi_fix_size(AngleIntExtFmt) - 1 downto 0) := psi_fix_from_real(0.5, AngleIntExtFmt);
92	  constant AngInt_1_0_c   : std_logic_vector(psi_fix_size(AngleIntExtFmt) - 1 downto 0) := psi_fix_from_real(1.0, AngleIntExtFmt);
93	
94	  -- *** Functions ***
95	  -- Cordic step for X
96	  function CordicStepX(xLast : std_logic_vector;
97	                       yLast : std_logic_vector;
98	                       shift : integer) return std_logic_vector is
99	    constant yShifted : std_logic_vector := psi_fix_shift_right(yLast, internal_fmt_g, shift, iterations_g - 1, internal_fmt_g, psi_fix_trunc, psi_fix_wrap, true);
100	  begin
101	
102	    if signed(yLast) < 0 then
103	      return psi_fix_sub(xLast, internal_fmt_g,
104	                       yShifted, internal_fmt_g,
105	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
106	    else
107	      return psi_fix_add(xLast, internal_fmt_g,
108	                       yShifted, internal_fmt_g,
109	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
110	
111	    end if;
112	  end function;
113	
114	  -- Cordic step for Y
115	  function CordicStepY(xLast : std_logic_vector;
116	                       yLast : std_logic_vector;
117	                       shift : integer) return std_logic_vector is
118	    constant xShifted : std_logic_vector := psi_fix_shift_right(xLast, internal_fmt_g, shift, iterations_g - 1, internal_fmt_g, psi_fix_trunc, psi_fix_wrap, true);
119	  begin
120	
121	    if signed(yLast) < 0 then
122	      return psi_fix_add(yLast, internal_fmt_g,
123	                       xShifted, internal_fmt_g,
124	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
125	    else
126	      return psi_fix_sub(yLast, internal_fmt_g,
127	                       xShifted, internal_fmt_g,
128	                       internal_fmt_g, psi_fix_trunc, psi_fix_wrap);
129	    end if;
130	  end function;
131	
132	  -- Cordic step for Z
133	  function CordicStepZ(zLast     : std_logic_vector;
134	                       yLast     : std_logic_vector;
135	                       iteration : integer) return std_logic_vector is
136	    constant Atan_c : std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0) := AngleTable_c(iteration);
137	  begin
138	    if signed(yLast) < 0 then
139	      return psi_fix_sub(zLast, angle_int_fmt_g,
140	                       Atan_c, angle_int_fmt_g,
141	                       angle_int_fmt_g, psi_fix_trunc, psi_fix_wrap);
142	    else
143	      return psi_fix_add(zLast, angle_int_fmt_g,
144	                       Atan_c, angle_int_fmt_g,
145	                       angle_int_fmt_g, psi_fix_trunc, psi_fix_wrap);
146	    end if;
147	  end function;
148	
149	  -- Attributes
150	  attribute use_dsp48 : string;
151	
152	  -- Types
153	  type IntArr_t is array (natural range <>) of std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
154	  type AngArr_t is array (natural range <>) of std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
155	
156	begin
157	  --------------------------------------------
158	  -- Assertions
159	  --------------------------------------------
160	  assert in_fmt_g.S = 1 report "psi_fix_cordic_vect: in_fmt_g must be signed" severity error;
161	  assert out_fmt_g.S = 0 report "psi_fix_cordic_vect: out_fmt_g must be unsigned" severity error;
162	  assert internal_fmt_g.S = 1 report "psi_fix_cordic_vect: internal_fmt_g must be signed" severity error;
163	  assert mode_g = "PIPELINED" or mode_g = "SERIAL" report "psi_fix_cordic_vect: mode_g must be PIPELINED or SERIAL" severity error;
164	  assert internal_fmt_g.I > in_fmt_g.I report "psi_fix_cordic_vect: internal_fmt_g must have at least one more bit than in_fmt_g" severity error;
165	  assert angle_fmt_g.S = 0 report "psi_fix_cordic_vect: angle_fmt_g must be unsigned" severity error;
166	  assert angle_int_fmt_g.S = 1 report "psi_fix_cordic_vect: angle_int_fmt_g must be signed" severity error;
167	
168	  --------------------------------------------
169	  -- Pipelined Implementation
170	  --------------------------------------------
171	  g_pipelined : if mode_g = "PIPELINED" generate
172	    signal XAbs, YAbs : std_logic_vector(psi_fix_size(AbsFmt_c) - 1 downto 0);
173	    attribute use_dsp48 of XAbs, YAbs : signal is "no"; -- Never do absolute value calculation in DSP, is too slow
174	    signal VldAbs     : std_logic;
175	    signal QuadAbs    : std_logic_vector(1 downto 0);
176	    signal X, Y       : IntArr_t(0 to iterations_g * pl_stg_per_iter_g);
177	    signal Z          : AngArr_t(0 to iterations_g * pl_stg_per_iter_g);
178	    signal Vld        : std_logic_vector(0 to iterations_g * pl_stg_per_iter_g);
179	    signal Quad       : t_aslv2(0 to iterations_g * pl_stg_per_iter_g);
180	  begin
181	    -- Pipelined implementation can take a sample every clock cycle
182	    rdy_o <= '1';
183	
184	    -- Implementation
185	    p_cordic_pipelined : process(clk_i)
186	    begin
187	      if rising_edge(clk_i) then
188	        if rst_i = '1' then
189	          Vld    <= (others => '0');
190	          VldAbs <= '0';
191	          vld_o  <= '0';
192	        else
193	          -- Input registers
194	          VldAbs  <= vld_i;
195	          XAbs    <= psi_fix_abs(dat_inp_i, in_fmt_g, AbsFmt_c, psi_fix_trunc, psi_fix_wrap); -- truncation is okay since internal format is usually bigger than input
196	          YAbs    <= psi_fix_abs(dat_qua_i, in_fmt_g, AbsFmt_c, psi_fix_trunc, psi_fix_wrap); -- truncation is okay since internal format is usually bigger than input
197	          QuadAbs <= dat_inp_i(dat_inp_i'left) & dat_qua_i(dat_qua_i'left);
198	
199	          -- Saturation
200	          X(0)    <= psi_fix_resize(XAbs, AbsFmt_c, internal_fmt_g, psi_fix_trunc, sat_g);
201	          Y(0)    <= psi_fix_resize(YAbs, AbsFmt_c, internal_fmt_g, psi_fix_trunc, sat_g);
202	          Z(0)    <= (others => '0');
203	          Quad(0) <= QuadAbs;
204	          Vld(0)  <= VldAbs;
205	
206	          -- Cordic iterations_g
207	          Vld(1 to Vld'high)   <= Vld(0 to Vld'high - 1);
208	          Quad(1 to Quad'high) <= Quad(0 to Quad'high - 1);
209	          for i in 0 to iterations_g - 1 loop
210	            X(i * pl_stg_per_iter_g + 1) <= CordicStepX(X(i * pl_stg_per_iter_g), Y(i * pl_stg_per_iter_g), i);
211	            Y(i * pl_stg_per_iter_g + 1) <= CordicStepY(X(i * pl_stg_per_iter_g), Y(i * pl_stg_per_iter_g), i);
212	            Z(i * pl_stg_per_iter_g + 1) <= CordicStepZ(Z(i * pl_stg_per_iter_g), Y(i * pl_stg_per_iter_g), i);
213	            -- Additional pipeline registers if required
214	            for k in 2 to pl_stg_per_iter_g loop
215	              X(i * pl_stg_per_iter_g + k) <= X(i * pl_stg_per_iter_g + k - 1);
216	              Y(i * pl_stg_per_iter_g + k) <= Y(i * pl_stg_per_iter_g + k - 1);
217	              Z(i * pl_stg_per_iter_g + k) <= Z(i * pl_stg_per_iter_g + k - 1);
218	            end loop;
219	          end loop;
220	
221	          -- Output
222	          vld_o <= Vld(iterations_g * pl_stg_per_iter_g);
223	          if gain_comp_g then
224	            dat_abs_o <= psi_fix_mult(X(iterations_g * pl_stg_per_iter_g), internal_fmt_g, GcCoef_c, GcFmt_c, out_fmt_g, round_g, sat_g);
225	          else
226	            dat_abs_o <= psi_fix_resize(X(iterations_g * pl_stg_per_iter_g), internal_fmt_g, out_fmt_g, round_g, sat_g);
227	          end if;
228	          case Quad(iterations_g * pl_stg_per_iter_g) is
229	            when "00"   => dat_ang_o <= psi_fix_resize(Z(iterations_g * pl_stg_per_iter_g), angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
230	            when "10"   => dat_ang_o <= psi_fix_sub(AngInt_0_5_c, AngleIntExtFmt, Z(iterations_g * pl_stg_per_iter_g), angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
231	            when "11"   => dat_ang_o <= psi_fix_add(AngInt_0_5_c, AngleIntExtFmt, Z(iterations_g * pl_stg_per_iter_g), angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
232	            when "01"   => dat_ang_o <= psi_fix_sub(AngInt_1_0_c, AngleIntExtFmt, Z(iterations_g * pl_stg_per_iter_g), angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
233	            when others => null;
234	          end case;
235	        end if;
236	      end if;
237	    end process;
238	  end generate;
239	
240	  --------------------------------------------
241	  -- Serial Implementation
242	  --------------------------------------------
243	  g_serial : if mode_g = "SERIAL" generate
244	    signal Xin, Yin : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
245	    signal XinVld   : std_logic;
246	    signal Quadin   : std_logic_vector(1 downto 0);
247	    signal X, Y     : std_logic_vector(psi_fix_size(internal_fmt_g) - 1 downto 0);
248	    signal Z        : std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0);
249	    signal CordVld  : std_logic;
250	    signal IterCnt  : integer range 0 to iterations_g - 1;
251	    signal Quad     : std_logic_vector(1 downto 0);
252	    constant Z0_c   : std_logic_vector(psi_fix_size(angle_int_fmt_g) - 1 downto 0) := (others => '0');
253	  begin
254	    rdy_o <= not XinVld;
255	
256	    p_cordic_serial : process(clk_i)
257	    begin
258	      if rising_edge(clk_i) then
259	        if rst_i = '1' then
260	          XinVld  <= '0';
261	          IterCnt <= 0;
262	          vld_o   <= '0';
263	          CordVld <= '0';
264	        else
265	          -- Input latching
266	          if XinVld = '0' and vld_i = '1' then
267	            XinVld <= '1';
268	            Xin    <= psi_fix_abs(dat_inp_i, in_fmt_g, internal_fmt_g, round_g, sat_g);
269	            Yin    <= psi_fix_abs(dat_qua_i, in_fmt_g, internal_fmt_g, round_g, sat_g);
270	            Quadin <= dat_inp_i(dat_inp_i'left) & dat_qua_i(dat_qua_i'left);
271	          end if;
272	
273	          -- CORDIC loop
274	          CordVld <= '0';
275	          if IterCnt = 0 then
276	            -- start of calculation
277	            if XinVld = '1' then
278	              X       <= CordicStepX(Xin, Yin, 0);
279	              Y       <= CordicStepY(Xin, Yin, 0);
280	              Quad    <= Quadin;
281	              Z       <= CordicStepZ(Z0_c, Yin, 0);
282	              IterCnt <= IterCnt + 1;
283	              XinVld  <= '0';
284	            end if;
285	          else
286	            -- Normal Calculation Step
287	            X <= CordicStepX(X, Y, IterCnt);
288	            Y <= CordicStepY(X, Y, IterCnt);
289	            Z <= CordicStepZ(Z, Y, IterCnt);
290	
291	            if IterCnt = iterations_g - 1 then
292	              IterCnt <= 0;
293	              CordVld <= '1';
294	            else
295	              IterCnt <= IterCnt + 1;
296	            end if;
297	          end if;
298	
299	          -- Output stage
300	          vld_o <= CordVld;
301	          if CordVld = '1' then
302	            if gain_comp_g then
303	              dat_abs_o <= psi_fix_mult(X, internal_fmt_g, GcCoef_c, GcFmt_c, out_fmt_g, round_g, sat_g);
304	            else
305	              dat_abs_o <= psi_fix_resize(X, internal_fmt_g, out_fmt_g, round_g, sat_g);
306	            end if;
307	            case Quad is
308	              when "00"   => dat_ang_o <= psi_fix_resize(Z, angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
309	              when "10"   => dat_ang_o <= psi_fix_sub(AngInt_0_5_c, AngleIntExtFmt, Z, angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
310	              when "11"   => dat_ang_o <= psi_fix_add(AngInt_0_5_c, AngleIntExtFmt, Z, angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
311	              when "01"   => dat_ang_o <= psi_fix_sub(AngInt_1_0_c, AngleIntExtFmt, Z, angle_int_fmt_g, angle_fmt_g, round_g, sat_g);
312	              when others => null;
313	            end case;
314	          end if;
315	        end if;
316	      end if;
317	    end process;
318	  end generate;
319	
320	end architecture;
321	
