      sat_g          => psi_fix_sat_from_string(sat_g),
      mode_g         => mode_g,
      in_fmt_g        => in_fmt_g,
      out_fmt_g       => out_fmt_g,
      internal_fmt_g  => internal_fmt_g,
      angle_fmt_g     => angle_fmt_g,
      angle_int_fmt_g  => angle_int_fmt_g,
